#!/bin/bash
set -e
echo "🔧 Fix design cartes + couvertures + doublons suggestions..."
cd "$(git rev-parse --show-toplevel)"
python3 - << 'INNER'
import base64, os
os.makedirs("src/components/book", exist_ok=True)
